// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.ir;

import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.LinkedHashSet;
import java.util.List;
import java.util.Set;

import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.algebra.BindingSetAssignment;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.LeftJoin;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.Union;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.BindingUniverse;
import org.eclipse.rdf4j.query.impl.MapBindingSet;
import org.junit.jupiter.api.Test;

class BindingShapeTest {
	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void statementPatternAssuresNonConstantVariables() {
		PlanIr ir = TupleExprToIr.convert(pattern("s", "p", "o"));
		BindingUniverse universe = ir.universe();
		BindingShape shape = ir.rootNode().bindings();

		assertTrue(shape.possible().contains(universe.symbol("s")));
		assertTrue(shape.assured().contains(universe.symbol("p")));
		assertTrue(shape.assured().contains(universe.symbol("o")));
	}

	@Test
	void unionOnlyAssuresVariablesAssuredByBothArms() {
		PlanIr ir = TupleExprToIr.convert(new Union(pattern("s", "p", "o"), pattern("s", "p", "x")));
		BindingUniverse universe = ir.universe();
		BindingShape shape = ir.rootNode().bindings();

		assertTrue(shape.possible().contains(universe.symbol("o")));
		assertTrue(shape.possible().contains(universe.symbol("x")));
		assertTrue(shape.assured().contains(universe.symbol("s")));
		assertFalse(shape.assured().contains(universe.symbol("o")));
		assertFalse(shape.assured().contains(universe.symbol("x")));
	}

	@Test
	void leftJoinMakesRightOnlyVariablesNullable() {
		PlanIr ir = TupleExprToIr.convert(new LeftJoin(pattern("s", "p1", "o"), pattern("s", "p2", "opt")));
		BindingUniverse universe = ir.universe();
		BindingShape shape = ir.rootNode().bindings();

		assertTrue(shape.assured().contains(universe.symbol("s")));
		assertFalse(shape.assured().contains(universe.symbol("opt")));
		assertTrue(shape.nullable().contains(universe.symbol("opt")));
	}

	@Test
	void joinAssuredMaskIsUnionOfChildAssuredMasks() {
		PlanIr ir = TupleExprToIr.convert(new Join(pattern("s", "p1", "o"), pattern("o", "p2", "x")));
		BindingUniverse universe = ir.universe();
		BindingShape shape = ir.rootNode().bindings();

		assertTrue(shape.assured().contains(universe.symbol("s")));
		assertTrue(shape.assured().contains(universe.symbol("x")));
	}

	@Test
	void statementPatternVariablesAreNotLocalBindOutputs() {
		PlanIr ir = TupleExprToIr.convert(pattern("s", "p", "o"));
		BindingUniverse universe = ir.universe();

		assertFalse(ir.rootNode().bindings().localBindOutputs().contains(universe.symbol("s")));
	}

	@Test
	void bindingSetAssignmentVariablesAreLocalBindOutputs() {
		BindingSetAssignment assignment = new BindingSetAssignment();
		assignment.setBindingNames(new LinkedHashSet<>(Set.of("drug")));
		MapBindingSet row = new MapBindingSet(1);
		row.addBinding("drug", VF.createIRI("urn:drug:1"));
		assignment.setBindingSets(List.<BindingSet>of(row));

		PlanIr ir = TupleExprToIr.convert(assignment);
		BindingUniverse universe = ir.universe();

		assertTrue(ir.rootNode().bindings().localBindOutputs().contains(universe.symbol("drug")));
	}

	private static StatementPattern pattern(String subject, String predicate, String object) {
		return new StatementPattern(new Var(subject), new Var(predicate), new Var(object));
	}
}
